#include <stdio.h>
#include <stdlib.h>

long long countSubarrays(int* arr, int n) {
    int countMap[3] = {0}; 
    int i = 0, j = 0;
    long long count = 0, distinctCount = 0;

    while (j < n) {
        if (countMap[arr[j]] == 0) {
            distinctCount++;
        }
        countMap[arr[j]]++;

        while (distinctCount == 3) {
            count += (n - j);
            countMap[arr[i]]--;
            if (countMap[arr[i]] == 0) {
                distinctCount--;
            }
            i++;
        }
        j++;
    }

    return count;
}

