function countSubarrays(arr) {
    // Initialize count for three distinct values (0, 1, 2)
    const count = [0, 0, 0];
    let subcount = 0;
    let back = 0;
    const n = arr.length;

    for (let front = 0; front < n; front++) {
        // Increment the count for the current element
        count[arr[front]]++;

        // While there is at least one of each element (0, 1, 2)
        while (Math.min(...count) > 0) {
            // Increment the subcount by the number of valid subarrays
            subcount += n - front;

            // Decrease the count of the element at the back pointer
            count[arr[back]]--;
            back++;
        }
    }

    return subcount;
}

